    Examples
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") == 3 
    '''
    import re
    import string
    p = re.compile('[0-9]*')
    p = p.match(txt)
    if p:
        return int(p.group())
    else:
        count = 0
        for letter in txt:
